// App.js
import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
  ScrollView,
  Linking,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';

WebBrowser.maybeCompleteAuthSession();

// ============================================================
// WARNING: Storing client_secret in a mobile app is a security
// risk. Mobile apps are considered "public clients" in OAuth 2.0
// and should use PKCE (Proof Key for Code Exchange) without a
// client_secret. The client_secret can be extracted from the
// app binary through reverse engineering.
//
// This implementation includes client_secret as requested,
// but for production use, consider:
// 1. Using PKCE flow without client_secret
// 2. Using a backend proxy to handle token exchange
// 3. Using a BFF (Backend for Frontend) pattern
// ============================================================

// OAuth 2.0 Configuration
const OAUTH_CONFIG = {
  clientId: 'your-client-id-here',
  // WARNING: client_secret should NOT be stored in mobile apps in production
  clientSecret: 'your-client-secret-here',
  authorizationEndpoint: 'https://your-oauth-server.com/authorize',
  tokenEndpoint: 'https://your-oauth-server.com/token',
  revocationEndpoint: 'https://your-oauth-server.com/revoke',
  userInfoEndpoint: 'https://your-oauth-server.com/userinfo',
  scopes: ['openid', 'profile', 'email', 'offline_access'],
  redirectUri: AuthSession.makeRedirectUri({
    scheme: 'myapp',
    path: 'oauth/callback',
  }),
};

// Storage keys
const STORAGE_KEYS = {
  ACCESS_TOKEN: '@oauth_access_token',
  REFRESH_TOKEN: '@oauth_refresh_token',
  TOKEN_EXPIRY: '@oauth_token_expiry',
  ID_TOKEN: '@oauth_id_token',
  USER_INFO: '@oauth_user_info',
};

// Token refresh buffer (refresh 5 minutes before expiry)
const TOKEN_REFRESH_BUFFER_SECONDS = 300;

// --- Token Storage Service ---
class TokenStorageService {
  static async saveTokens(tokenResponse) {
    try {
      const expiryTime = Date.now() + (tokenResponse.expires_in || 3600) * 1000;

      const pairs = [
        [STORAGE_KEYS.ACCESS_TOKEN, tokenResponse.access_token],
        [STORAGE_KEYS.TOKEN_EXPIRY, expiryTime.toString()],
      ];

      if (tokenResponse.refresh_token) {
        pairs.push([STORAGE_KEYS.REFRESH_TOKEN, tokenResponse.refresh_token]);
      }

      if (tokenResponse.id_token) {
        pairs.push([STORAGE_KEYS.ID_TOKEN, tokenResponse.id_token]);
      }

      await AsyncStorage.multiSet(pairs);
      return true;
    } catch (error) {
      console.error('Failed to save tokens:', error);
      return false;
    }
  }

  static async getAccessToken() {
    try {
      return await AsyncStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN);
    } catch (error) {
      console.error('Failed to get access token:', error);
      return null;
    }
  }

  static async getRefreshToken() {
    try {
      return await AsyncStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN);
    } catch (error) {
      console.error('Failed to get refresh token:', error);
      return null;
    }
  }

  static async getTokenExpiry() {
    try {
      const expiry = await AsyncStorage.getItem(STORAGE_KEYS.TOKEN_EXPIRY);
      return expiry ? parseInt(expiry, 10) : null;
    } catch (error) {
      console.error('Failed to get token expiry:', error);
      return null;
    }
  }

  static async isTokenExpired() {
    const expiry = await this.getTokenExpiry();
    if (!expiry) return true;
    return Date.now() >= expiry - TOKEN_REFRESH_BUFFER_SECONDS * 1000;
  }

  static async saveUserInfo(userInfo) {
    try {
      await AsyncStorage.setItem(STORAGE_KEYS.USER_INFO, JSON.stringify(userInfo));
    } catch (error) {
      console.error('Failed to save user info:', error);
    }
  }

  static async getUserInfo() {
    try {
      const info = await AsyncStorage.getItem(STORAGE_KEYS.USER_INFO);
      return info ? JSON.parse(info) : null;
    } catch (error) {
      console.error('Failed to get user info:', error);
      return null;
    }
  }

  static async clearAll() {
    try {
      await AsyncStorage.multiRemove(Object.values(STORAGE_KEYS));
      return true;
    } catch (error) {
      console.error('Failed to clear tokens:', error);
      return false;
    }
  }
}

// --- OAuth Service ---
class OAuthService {
  static async exchangeCodeForTokens(authorizationCode, codeVerifier) {
    try {
      const body = new URLSearchParams({
        grant_type: 'authorization_code',
        code: authorizationCode,
        redirect_uri: OAUTH_CONFIG.redirectUri,
        client_id: OAUTH_CONFIG.clientId,
        client_secret: OAUTH_CONFIG.clientSecret,
        ...(codeVerifier && { code_verifier: codeVerifier }),
      });

      const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: body.toString(),
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(
          errorData.error_description || errorData.error || `Token exchange failed: ${response.status}`
        );
      }

      const tokenData = await response.json();
      await TokenStorageService.saveTokens(tokenData);
      return tokenData;
    } catch (error) {
      console.error('Token exchange error:', error);
      throw error;
    }
  }

  static async refreshAccessToken() {
    try {
      const refreshToken = await TokenStorageService.getRefreshToken();

      if (!refreshToken) {
        throw new Error('No refresh token available');
      }

      const body = new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
        client_id: OAUTH_CONFIG.clientId,
        client_secret: OAUTH_CONFIG.clientSecret,
        scope: OAUTH_CONFIG.scopes.join(' '),
      });

      const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: body.toString(),
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));

        if (response.status === 400 && errorData.error === 'invalid_grant') {
          await TokenStorageService.clearAll();
          throw new Error('REFRESH_TOKEN_EXPIRED');
        }

        throw new Error(
          errorData.error_description || errorData.error || `Token refresh failed: ${response.status}`
        );
      }

      const tokenData = await response.json();
      await TokenStorageService.saveTokens(tokenData);
      console.log('Token refreshed successfully');
      return tokenData;
    } catch (error) {
      console.error('Token refresh error:', error);
      throw error;
    }
  }

  static async getValidAccessToken() {
    const isExpired = await TokenStorageService.isTokenExpired();

    if (isExpired) {
      try {
        const tokenData = await this.refreshAccessToken();
        return tokenData.access_token;
      } catch (error) {
        if (error.message === 'REFRESH_TOKEN_EXPIRED') {
          throw error;
        }
        const accessToken = await TokenStorageService.getAccessToken();
        if (accessToken) return accessToken;
        throw error;
      }
    }

    return await TokenStorageService.getAccessToken();
  }

  static async fetchUserInfo() {
    try {
      const accessToken = await this.getValidAccessToken();

      const response = await fetch(OAUTH_CONFIG.userInfoEndpoint, {
        headers: {
          Authorization: `Bearer ${accessToken}`,
        },
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch user info: ${response.status}`);
      }

      const userInfo = await response.json();
      await TokenStorageService.saveUserInfo(userInfo);
      return userInfo;
    } catch (error) {
      console.error('User info fetch error:', error);
      throw error;
    }
  }

  static async revokeToken() {
    try {
      const accessToken = await TokenStorageService.getAccessToken();
      const refreshToken = await TokenStorageService.getRefreshToken();

      const revokePromises = [];

      if (refreshToken) {
        revokePromises.push(
          fetch(OAUTH_CONFIG.revocationEndpoint, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/x-www-form-urlencoded',
            },
            body: new URLSearchParams({
              token: refreshToken,
              token_type_hint: 'refresh_token',
              client_id: OAUTH_CONFIG.clientId,
              client_secret: OAUTH_CONFIG.clientSecret,
            }).toString(),
          })
        );
      }

      if (accessToken) {
        revokePromises.push(
          fetch(OAUTH_CONFIG.revocationEndpoint, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/x-www-form-urlencoded',
            },
            body: new URLSearchParams({
              token: accessToken,
              token_type_hint: 'access_token',
              client_id: OAUTH_CONFIG.clientId,
              client_secret: OAUTH_CONFIG.clientSecret,
            }).toString(),
          })
        );
      }

      await Promise.allSettled(revokePromises);
      await TokenStorageService.clearAll();
    } catch (error) {
      console.error('Token revocation error:', error);
      await TokenStorageService.clearAll();
    }
  }
}

// --- Authenticated API Client ---
class ApiClient {
  static async request(url, options = {}) {
    try {
      const accessToken = await OAuthService.getValidAccessToken();

      const response = await fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${accessToken}`,
        },
      });

      if (response.status === 401) {
        try {
          const newTokenData = await OAuthService.refreshAccessToken();

          const retryResponse = await fetch(url, {
            ...options,
            headers: {
              ...options.headers,
              Authorization: `Bearer ${newTokenData.access_token}`,
            },
          });

          return retryResponse;
        } catch (refreshError) {
          throw new Error('AUTHENTICATION_REQUIRED');
        }
      }

      return response;
    } catch (error) {
      if (error.message === 'REFRESH_TOKEN_EXPIRED' || error.message === 'AUTHENTICATION_REQUIRED') {
        throw error;
      }
      throw error;
    }
  }

  static async get(url, options = {}) {
    return this.request(url, { ...options, method: 'GET' });
  }

  static async post(url, data, options = {}) {
    return this.request(url, {
      ...options,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
      body: JSON.stringify(data),
    });
  }
}

// --- Custom Hook: useAuth ---
function useAuth() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [userInfo, setUserInfo] = useState(null);
  const [error, setError] = useState(null);
  const refreshTimerRef = useRef(null);

  const discovery = {
    authorizationEndpoint: OAUTH_CONFIG.authorizationEndpoint,
    tokenEndpoint: OAUTH_CONFIG.tokenEndpoint,
    revocationEndpoint: OAUTH_CONFIG.revocationEndpoint,
  };

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: OAUTH_CONFIG.clientId,
      scopes: OAUTH_CONFIG.scopes,
      redirectUri: OAUTH_CONFIG.redirectUri,
      responseType: AuthSession.ResponseType.Code,
      usePKCE: true,
      extraParams: {
        access_type: 'offline',
        prompt: 'consent',
      },
    },
    discovery
  );

  const scheduleTokenRefresh = useCallback(async () => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }

    const expiry = await TokenStorageService.getTokenExpiry();
    if (!expiry) return;

    const refreshTime = expiry - TOKEN_REFRESH_BUFFER_SECONDS * 1000 - Date.now();
    const delay = Math.max(refreshTime, 0);

    console.log(`Scheduling token refresh in ${Math.round(delay / 1000)} seconds`);

    refreshTimerRef.current = setTimeout(async () => {
      try {
        await OAuthService.refreshAccessToken();
        console.log('Automatic token refresh successful');
        scheduleTokenRefresh();
      } catch (err) {
        console.error('Automatic token refresh failed:', err);
        if (err.message === 'REFRESH_TOKEN_EXPIRED') {
          setIsAuthenticated(false);
          setUserInfo(null);
          Alert.alert(
            'Session Expired',
            'Your session has expired. Please log in again.',
            [{ text: 'OK' }]
          );
        }
      }
    }, delay);
  }, []);

  const checkExistingAuth = useCallback(async () => {
    try {
      setIsLoading(true);
      const accessToken = await TokenStorageService.getAccessToken();

      if (accessToken) {
        const isExpired = await TokenStorageService.isTokenExpired();

        if (isExpired) {
          try {
            await OAuthService.refreshAccessToken();
          } catch (refreshError) {
            await TokenStorageService.clearAll();
            setIsAuthenticated(false);
            setIsLoading(false);
            return;
          }
        }

        const savedUserInfo = await TokenStorageService.getUserInfo();
        if (savedUserInfo) {
          setUserInfo(savedUserInfo);
        } else {
          try {
            const fetchedUserInfo = await OAuthService.fetchUserInfo();
            setUserInfo(fetchedUserInfo);
          } catch (e) {
            console.warn('Could not fetch user info:', e);
          }
        }

        setIsAuthenticated(true);
        scheduleTokenRefresh();
      }
    } catch (err) {
      console.error('Auth check error:', err);
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, [scheduleTokenRefresh]);

  useEffect(() => {
    checkExistingAuth();
    return () => {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
    };
  }, [checkExistingAuth]);

  useEffect(() => {
    const handleAuthResponse = async () => {
      if (response?.type === 'success') {
        const { code } = response.params;
        setIsLoading(true);
        setError(null);

        try {
          await OAuthService.exchangeCodeForTokens(
            code,
            request?.codeVerifier
          );

          try {
            const fetchedUserInfo = await OAuthService.fetchUserInfo();
            setUserInfo(fetchedUserInfo);
          } catch (e) {
            console.warn('Could not fetch user info after login:', e);
          }

          setIsAuthenticated(true);
          scheduleTokenRefresh();
        } catch (err) {
          console.error('Authentication error:', err);
          setError(err.message);
          Alert.alert('Authentication Error', err.message);
        } finally {
          setIsLoading(false);
        }
      } else if (response?.type === 'error') {
        setError(response.error?.message || 'Authentication failed');
        Alert.alert(
          'Authentication Error',
          response.error?.message || 'Authentication failed'
        );
      } else if (response?.type === 'dismiss') {
        console.log('Authentication was dismissed by user');
      }
    };

    handleAuthResponse();
  }, [response, request, scheduleTokenRefresh]);

  const login = useCallback(async () => {
    setError(null);
    try {
      await promptAsync();
    } catch (err) {
      setError(err.message);
      Alert.alert('Login Error', err.message);
    }
  }, [promptAsync]);

  const logout = useCallback(async () => {
    setIsLoading(true);
    try {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
      await OAuthService.revokeToken();
      setIsAuthenticated(false);
      setUserInfo(null);
      setError(null);
    } catch (err) {
      console.error('Logout error:', err);
      setIsAuthenticated(false);
      setUserInfo(null);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const refreshUserInfo = useCallback(async () => {
    try {
      const fetchedUserInfo = await OAuthService.fetchUserInfo();
      setUserInfo(fetchedUserInfo);
      return fetchedUserInfo;
    } catch (err) {
      console.error('Failed to refresh user info:', err);
      throw err;
    }
  }, []);

  return {
    isAuthenticated,
    isLoading,
    userInfo,
    error,
    login,
    logout,
    refreshUserInfo,
    canLogin: !!request,
  };
}

// --- Login Screen Component ---
function LoginScreen({ onLogin, canLogin, isLoading, error }) {
  return (
    <View style={styles.centerContainer}>
      <View style={styles.loginCard}>
        <Text style={styles.appTitle}>MyApp</Text>
        <Text style={styles.appSubtitle}>Sign in to continue</Text>

        {error && (
          <View style={styles.errorContainer}>
            <Text style={styles.errorText}>{error}</Text>
          </View>
        )}

        <TouchableOpacity
          style={[styles.loginButton, (!canLogin || isLoading) && styles.disabledButton]}
          onPress={onLogin}
          disabled={!canLogin || isLoading}
        >
          {isLoading ? (
            <ActivityIndicator color="#FFFFFF" />
          ) : (
            <Text style={styles.loginButtonText}>Sign In with OAuth</Text>
          )}
        </TouchableOpacity>

        <Text style={styles.securityNote}>
          🔒 Secured with OAuth 2.0 Authorization Code Flow with PKCE
        </Text>
      </View>
    </View>
  );
}

// --- Home Screen Component ---
function HomeScreen({ userInfo, onLogout, onRefreshUserInfo, isLoading }) {
  const [apiResult, setApiResult] = useState(null);
  const [apiLoading, setApiLoading] = useState(false);

  const makeApiCall = async () => {
    setApiLoading(true);
    try {
      const response = await ApiClient.get('https://your-api.com/protected-resource');
      const data = await response.json();
      setApiResult(JSON.stringify(data, null, 2));
    } catch (err) {
      if (err.message === 'AUTHENTICATION_REQUIRED') {
        Alert.alert('Session Expired', 'Please log in again.');
      } else {
        setApiResult(`Error: ${err.message}`);
      }
    } finally {
      setApiLoading(false);
    }
  };

  return (
    <ScrollView style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.headerTitle}>Welcome!</Text>
        <TouchableOpacity
          style={styles.logoutButton}
          onPress={onLogout}
          disabled={isLoading}
        >
          {isLoading ? (
            <ActivityIndicator color="#FF3B30" size="small" />
          ) : (
            <Text style={styles.logoutButtonText}>Sign Out</Text>
          )}
        </TouchableOpacity>
      </View>

      {userInfo && (
        <View style={styles.userCard}>
          <Text style={styles.sectionTitle}>User Profile</Text>
          <View style={styles.userInfoRow}>
            <Text style={styles.label}>Name:</Text>
            <Text style={styles.value}>{userInfo.name || 'N/A'}</Text>
          </View>
          <View style={styles.userInfoRow}>
            <Text style={styles.label}>Email:</Text>
            <Text style={styles.value}>{userInfo.email || 'N/A'}</Text>
          </View>
          <View style={styles.userInfoRow}>
            <Text style={styles.label}>Subject:</Text>
            <Text style={styles.value}>{userInfo.sub || 'N/A'}</Text>
          </View>
          <TouchableOpacity
            style={styles.refreshButton}
            onPress={onRefreshUserInfo}
          >
            <Text style={styles.refreshButtonText}>Refresh Profile</Text>
          </TouchableOpacity>
        </View>
      )}

      <View style={styles.apiCard}>
        <Text style={styles.sectionTitle}>API Test</Text>
        <TouchableOpacity
          style={styles.apiButton}
          onPress={makeApiCall}
          disabled={apiLoading}
        >
          {apiLoading ? (
            <ActivityIndicator color="#FFFFFF" />
          ) : (
            <Text style={styles.apiButtonText}>Call Protected API</Text>
          )}
        </TouchableOpacity>

        {apiResult && (
          <View style={styles.apiResultContainer}>
            <Text style={styles.apiResultText}>{apiResult}</Text>
          </View>
        )}
      </View>

      <View style={styles.infoCard}>
        <Text style={styles.sectionTitle}>Token Info</Text>
        <Text style={styles.infoText}>
          ✅ Automatic token refresh is active{'\n'}
          ✅ Tokens are securely stored{'\n'}
          ✅ PKCE flow enabled
        </Text>
      </View>
    </ScrollView>
  );
}

// --- Main App Component ---
export default function App() {
  const {
    isAuthenticated,
    isLoading,
    userInfo,
    error,
    login,
    logout,
    refreshUserInfo,
    canLogin,
  } = useAuth();

  if (isLoading && !isAuthenticated) {
    return (
      <View style={styles.centerContainer}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Loading...</Text>
      </View>
    );
  }

  if (isAuthenticated) {
    return (
      <HomeScreen
        userInfo={userInfo}
        onLogout={logout}
        onRefreshUserInfo={refreshUserInfo}
        isLoading={isLoading}
      />
    );
  }

  return (
    <LoginScreen
      onLogin={login}
      canLogin={canLogin}
      isLoading={isLoading}
      error={error}
    />
  );
}

